using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ── Build the IChatClient via MEAI ─────────────────────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────────
var notebook = new Notebook();
using var httpClient = new HttpClient();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            WebSearchAsync(httpClient, query),
        "web_search",
        "Searches the web for information about a query and returns a list of result snippets."),

    AIFunctionFactory.Create(
        ([Description("A concise title for the note")] string title,
         [Description("The content of the note")] string content) =>
            notebook.AddNote(title, content),
        "add_note",
        "Saves a research note with a title and content. Use this to record important findings."),

    AIFunctionFactory.Create(
        () => notebook.GetNotes(),
        "get_notes",
        "Retrieves all notes that have been saved so far."),
};

// ── Agent ──────────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

// ── Prompt the user ────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent                 ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.Write("\nEnter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var userMessage = $"""
    Research the following topic thoroughly: "{topic}"

    Instructions:
    1. Use the web_search tool multiple times with different queries to gather information.
    2. Use the add_note tool to record key findings as you go.
    3. After you have gathered enough information, use get_notes to review your notes.
    4. Finally, provide a comprehensive summary of your findings organized with clear headings.
    """;

// ── Run the agent with streaming ───────────────────────────────────
var session = await agent.CreateSessionAsync(Guid.NewGuid().ToString());

await foreach (var update in agent.RunStreamingAsync(
    userMessage, session))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n── Research complete ──");

// ═══════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════

static async Task<string> WebSearchAsync(HttpClient httpClient, string query)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  🔍 Searching: {query}");
    Console.ResetColor();

    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        var response = await httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        return ParseSearchResults(html);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static string ParseSearchResults(string html)
{
    var results = new StringBuilder();
    int count = 0;

    // Extract result snippets from DuckDuckGo HTML
    var snippetTag = "result__snippet";
    var titleTag = "result__a";
    int pos = 0;

    while (count < 6 && (pos = html.IndexOf(snippetTag, pos, StringComparison.Ordinal)) >= 0)
    {
        pos += snippetTag.Length;

        // Find the closing > of the tag
        int tagEnd = html.IndexOf('>', pos);
        if (tagEnd < 0) break;

        // Find the title above this snippet
        int titleStart = html.LastIndexOf(titleTag, pos, StringComparison.Ordinal);
        string title = "";
        if (titleStart >= 0)
        {
            int tTagEnd = html.IndexOf('>', titleStart);
            int tTagClose = html.IndexOf('<', tTagEnd + 1);
            if (tTagEnd >= 0 && tTagClose > tTagEnd)
            {
                title = StripHtml(html[(tTagEnd + 1)..tTagClose]).Trim();
            }
        }

        // Extract snippet text
        int snippetEnd = html.IndexOf("</", tagEnd, StringComparison.Ordinal);
        if (snippetEnd < 0) break;

        var snippet = StripHtml(html[(tagEnd + 1)..snippetEnd]).Trim();

        if (!string.IsNullOrWhiteSpace(snippet))
        {
            count++;
            results.AppendLine($"[{count}] {title}");
            results.AppendLine($"    {snippet}");
            results.AppendLine();
        }
    }

    return count > 0
        ? results.ToString()
        : "No results found for this query.";
}

static string StripHtml(string html)
{
    var sb = new StringBuilder(html.Length);
    bool inTag = false;
    foreach (var ch in html)
    {
        if (ch == '<') { inTag = true; continue; }
        if (ch == '>') { inTag = false; continue; }
        if (!inTag) sb.Append(ch);
    }

    return System.Net.WebUtility.HtmlDecode(sb.ToString());
}

// ═══════════════════════════════════════════════════════════════════
// Notebook — simple in-memory note-taking tool
// ═══════════════════════════════════════════════════════════════════

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public string AddNote(string title, string content)
